import { useState } from "react";
import { Outlet } from "react-router-dom";
import Sidebar from "./components/Sidebar";
import Topbar from "./components/Topbar";
import { motion, AnimatePresence } from "framer-motion";
import useAutoLogout from "../hooks/useAutoLogout";

export default function AdminLayout() {
  const [sidebarOpen, setSidebarOpen] = useState(false);

  // Track inactivity (10 minutes defaults in hook)
  useAutoLogout();

  return (
    <div className="min-h-screen bg-[#f8fafc] text-gray-900 font-sans flex overflow-hidden lg:overflow-visible">

      {/* Desktop Sidebar (Fixed) */}
      <div className="hidden lg:block fixed top-0 left-0 h-screen w-64 z-30 border-r border-[#e2e8f0] bg-white">
        <Sidebar />
      </div>

      {/* Mobile Drawer & Overlay */}
      <AnimatePresence>
        {sidebarOpen && (
          <>
            <motion.div
              initial={{ opacity: 0 }}
              animate={{ opacity: 1 }}
              exit={{ opacity: 0 }}
              className="fixed inset-0 bg-gray-900/40 backdrop-blur-sm z-[60] lg:hidden"
              onClick={() => setSidebarOpen(false)}
            />
            <motion.div
              initial={{ x: "-100%" }}
              animate={{ x: 0 }}
              exit={{ x: "-100%" }}
              transition={{ type: "spring", damping: 25, stiffness: 200 }}
              className="fixed inset-y-0 left-0 z-[70] w-72 lg:hidden bg-white shadow-2xl border-r border-[#e2e8f0]"
            >
              <Sidebar onNavigate={() => setSidebarOpen(false)} />
            </motion.div>
          </>
        )}
      </AnimatePresence>

      {/* Main Content Area */}
      <div className="flex-1 lg:ml-64 flex flex-col min-h-screen w-full relative">
        <Topbar onMenuClick={() => setSidebarOpen(true)} />

        <main className="flex-1 p-4 md:p-8 overflow-y-auto">
          <div className="max-w-7xl mx-auto">
            <Outlet />
          </div>
        </main>
      </div>
    </div>
  );
}

import { Navigate, useNavigate } from "react-router-dom";
import { ShieldAlert, ArrowLeft, Layout } from "lucide-react";

export default function AdminRoute({ children }) {
  const token = localStorage.getItem("adminToken");
  const adminUser = JSON.parse(localStorage.getItem("adminUser") || "null");

  if (!token) {
    return <Navigate to="/admin/login" replace />;
  }

  if (adminUser && adminUser.role !== "admin" && adminUser.isAdmin !== true) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-white text-[#0f172a] px-6">
        <div className="max-w-[480px] w-full text-center space-y-12">

          <div className="flex justify-center">
             <div className="h-24 w-24 rounded-[2.5rem] bg-[#0f172a] text-red-500 flex items-center justify-center shadow-sm ">
                <ShieldAlert size={48} strokeWidth={2.5} />
             </div>
          </div>

          <div className="space-y-4">
            <h1 className="text-4xl font-black uppercase tracking-tighter leading-none">
              Unauthorized Update
            </h1>
            <p className="text-[12px] font-black text-gray-400 uppercase tracking-[0.4em] px-8 leading-relaxed">
              Your user iduser lacks the high-level clearance required to access this node.
            </p>
          </div>

          <div className="flex flex-col gap-3">
             <button
                onClick={() => (window.location.href = "/")}
                className="w-full h-18 bg-[#0f172a] text-[#1e3a8a] rounded-full font-black uppercase tracking-widest text-[12px] flex items-center justify-center gap-3 shadow-xl hover:-translate-y-1 transition-all"
             >
                <ArrowLeft size={18} strokeWidth={3} /> Return to Public Grid
             </button>

             <button
                onClick={() => (window.location.href = "/admin/login")}
                className="w-full h-18 bg-[#f1f5f9] text-gray-400 rounded-full font-black uppercase tracking-widest text-[11px] flex items-center justify-center gap-3 hover:bg-[#0f172a] hover:text-white transition-all"
             >
                <Layout size={18} /> Switch Clearing Record
             </button>
          </div>

          <div className="pt-12 flex justify-center gap-5">
             <div className="flex items-center gap-2 text-[9px] font-black text-gray-300 uppercase tracking-widest">
                <div className="h-1.5 w-1.5 rounded-full bg-red-500" /> Security Locked
             </div>
             <div className="flex items-center gap-2 text-[9px] font-black text-gray-300 uppercase tracking-widest">
                <div className="h-1.5 w-1.5 rounded-full bg-[#0f172a]" /> Trace ID: {Math.random().toString(36).slice(2, 10).toUpperCase()}
             </div>
          </div>
        </div>
      </div>
    );
  }

  return children;
}

import { useState, useEffect, createElement } from "react";
import { api } from "../../api/client";
import { AreaChart, Area, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";
import { DollarSign, ShoppingBag, Users as UsersIcon, ArrowUpRight, ArrowDownRight, Activity } from "lucide-react";
import toast from "react-hot-toast";
import Button from "../../components/ui/Button";

export default function Dashboard() {
  const [stats, setStats] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const res = await api.get("/admin/stats");
        setStats(res || null);
      } catch {
        toast.error("Analytics fetch failed");
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading || !stats) {
    return (
      <div className="space-y-6 animate-pulse">
        <div className="h-8 w-1/4 bg-gray-200 rounded-md" />
        <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
          {[1,2,3].map((i) => <div key={i} className="h-32 bg-white rounded-xl border border-gray-100" />)}
        </div>
        <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">
           <div className="h-80 bg-white rounded-xl border border-gray-100" />
           <div className="h-80 bg-white rounded-xl border border-gray-100" />
        </div>
      </div>
    );
  }

  const StatCard = ({ title, value, icon: Icon, trend, isPositive }) => (
    <div className="bg-white rounded-xl border border-[#e2e8f0] p-5 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex justify-between items-start">
        <div className="space-y-3">
          <p className="text-sm font-medium text-gray-500">{title}</p>
          <p className="text-2xl font-semibold text-gray-900">{value}</p>

          <div className={`flex items-center gap-1 text-xs font-medium ${isPositive ? "text-emerald-600" : "text-rose-600"}`}>
            {isPositive ? <ArrowUpRight size={14} /> : <ArrowDownRight size={14} />}
            <span>{trend}</span>
            <span className="text-gray-400 ml-1">vs last month</span>
          </div>
        </div>
        <div className="w-10 h-10 rounded-lg bg-blue-50 text-blue-600 flex items-center justify-center">
          {createElement(Icon, { size: 20 })}
        </div>
      </div>
    </div>
  );

  const handleDownloadReport = async () => {
    try {
      toast.loading("Generating report...", { id: "export" });
      const response = await api.get("/admin/orders/export", { responseType: "blob" });

      const url = window.URL.createObjectURL(new Blob([response]));
      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download", `orders_report_${new Date().toISOString().split('T')[0]}.csv`);
      document.body.appendChild(link);
      link.click();
      link.remove();

      toast.success("Report downloaded", { id: "export" });
    } catch (err) {
      toast.error("Export failure", { id: "export" });
    }
  };

  return (
    <div className="space-y-6">

      {/* Header */}
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h1 className="text-2xl font-bold text-gray-900 tracking-tight">Overview</h1>
          <p className="text-sm text-gray-500 mt-1">Here's what's happening with your store today.</p>
        </div>

        <div className="flex items-center gap-3">
          <Button variant="outline" onClick={handleDownloadReport}>
            Download Report
          </Button>
          <Button variant="primary">
            <Activity size={16} /> Manage Analytics
          </Button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
        <StatCard 
          title="Total Revenue" 
          value={`₹${Math.floor(stats?.totalRevenue || 0).toLocaleString()}`} 
          icon={DollarSign} 
          trend="12.5%" 
          isPositive={true} 
        />
        <StatCard 
          title="Active Orders" 
          value={stats?.totalOrders || 0} 
          icon={ShoppingBag} 
          trend="8.2%" 
          isPositive={true} 
        />
        <StatCard 
          title="Total Customers" 
          value={stats?.totalUsers || 0} 
          icon={UsersIcon} 
          trend="2.4%" 
          isPositive={false} 
        />
      </div>

      {/* Charts Layer */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-5">

        {/* Revenue Area Chart */}
        <div className="bg-white rounded-xl border border-[#e2e8f0] p-5 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-base font-semibold text-gray-900">Revenue Performance</h2>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={stats?.revenueData || []} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <defs>
                  <linearGradient id="colorRev" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#2563eb" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#2563eb" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "#6b7280" }} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "#6b7280" }} />
                <Tooltip 
                  contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }} 
                  itemStyle={{ color: '#0f172a', fontWeight: '600' }}
                />
                <Area type="monotone" dataKey="revenue" stroke="#2563eb" strokeWidth={2} fillOpacity={1} fill="url(#colorRev)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Orders Bar Chart */}
        <div className="bg-white rounded-xl border border-[#e2e8f0] p-5 shadow-sm">
          <div className="flex items-center justify-between mb-6">
            <h2 className="text-base font-semibold text-gray-900">Order Volume</h2>
          </div>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={stats?.orderData || []} margin={{ top: 0, right: 0, left: -20, bottom: 0 }}>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "#6b7280" }} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{ fontSize: 12, fill: "#6b7280" }} />
                <Tooltip 
                  cursor={{ fill: '#f8fafc' }}
                  contentStyle={{ borderRadius: '8px', border: '1px solid #e2e8f0', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                  itemStyle={{ color: '#0f172a', fontWeight: '600' }}
                />
                <Bar dataKey="orders" fill="#0f172a" radius={[4, 4, 0, 0]} maxBarSize={40} />
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>

      </div>
    </div>
  );
}

import { useMemo, useState, useEffect } from "react";
import { api } from "../../api/client";
import { mapOffer } from "../../api/dynamicMapper";
import { uploadImage } from "../../api/upload";
import { Plus, Edit2, Trash2, Sparkles, RefreshCw, X, Tag, Calendar, Users, Info, ArrowRight, ShieldCheck, Activity } from "lucide-react";
import toast from "react-hot-toast";
import Button from "../../components/ui/Button";

const defaultForm = {
  title: "",
  couponCode: "",
  discountType: "percentage",
  discountValue: "",
  applyTo: "all",
  applyToCategory: "",
  applyToProductId: "",
  startDate: "",
  endDate: "",
  usageLimit: "",
  perUserLimit: "",
  isActive: true,
  image: "",
  link: "",
  description: "",
  minOrderAmount: "",
  maxDiscount: "",
};

export default function Offers() {
  const [offers, setOffers] = useState([]);
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);
  const [formOpen, setFormOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [errors, setErrors] = useState({});
  const [samplePrice, setSamplePrice] = useState(999);
  const [formData, setFormData] = useState(defaultForm);

  const fetchOffers = async () => {
    try {
      setLoading(true);
      const res = await api.get("/admin/offers");
      const data = res.data || res || [];
      setOffers(
        Array.isArray(data)
          ? data.map(mapOffer).map((o, i) => ({ ...o, raw: data[i] }))
          : []
      );
    } catch {
      toast.error("Marketing order sync failed");
    } finally {
      setLoading(false);
    }
  };

  const fetchProducts = async () => {
    try {
      const res = await api.get("/admin/products");
      const data = res.data || res.items || res || [];
      setProducts(Array.isArray(data) ? data : []);
    } catch {
      setProducts([]);
    }
  };

  useEffect(() => {
    fetchOffers();
    fetchProducts();
  }, []);

  const updateField = (key, value) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
    setErrors((prev) => ({ ...prev, [key]: "" }));
  };

  const openCreate = () => {
    setEditingId(null);
    setErrors({});
    setFormData(defaultForm);
    setFormOpen(true);
  };

  const openEdit = (offer) => {
    const raw = offer.raw || {};
    setEditingId(offer.id);
    setErrors({});
    setFormData({
      title: raw.title || "",
      couponCode: raw.couponCode || "",
      discountType: raw.discountType || "percentage",
      discountValue: raw.discountValue ?? "",
      applyTo: raw.applyTo || "all",
      applyToCategory: raw.applyToCategory || "",
      applyToProductId: raw.applyToProductId || "",
      startDate: raw.startDate?.split("T")[0] || "",
      endDate: raw.endDate?.split("T")[0] || "",
      usageLimit: raw.usageLimit ?? "",
      perUserLimit: raw.perUserLimit ?? "",
      isActive: raw.isActive ?? true,
      image: raw.image || "",
      link: raw.link || "",
      description: raw.description || "",
      minOrderAmount: raw.minOrderAmount ?? "",
      maxDiscount: raw.maxDiscount ?? "",
    });
    setFormOpen(true);
  };

  const generateCoupon = () => {
    const prefix = (formData.title || "DEAL")
      .replace(/[^a-zA-Z0-9]/g, "")
      .toUpperCase()
      .slice(0, 6);
    const suffix = Math.random().toString(36).slice(2, 6).toUpperCase();
    updateField("couponCode", `${prefix}${suffix}`);
  };

  const validateForm = () => {
    const next = {};
    if (!formData.title.trim()) next.title = "Identifier required";
    if (!formData.couponCode.trim()) next.couponCode = "Code order required";
    const discountValue = Number(formData.discountValue || 0);
    if (!Number.isFinite(discountValue) || discountValue <= 0) next.discountValue = "Mathematical value required";
    if (!formData.startDate || !formData.endDate) next.endDate = "Temporal range required";
    setErrors(next);
    return Object.keys(next).length === 0;
  };

  const discountPreview = useMemo(() => {
    const val = Number(formData.discountValue || 0);
    const price = Number(samplePrice || 0);
    const maxD = Number(formData.maxDiscount || Infinity);
    if (!val || !price) return 0;

    let discount = 0;
    if (formData.discountType === "flat") {
      discount = Math.min(val, price);
    } else {
      discount = Math.round((price * val) / 100);
      if (maxD > 0) discount = Math.min(discount, maxD);
    }
    return discount;
  }, [formData.discountValue, formData.discountType, formData.maxDiscount, samplePrice]);

  const handleImageUpload = async (file) => {
    if (!file) return;
    setUploading(true);
    try {
      const imageUrl = await uploadImage(file);
      updateField("image", imageUrl);
      toast.success("Visual Save Complete");
    } catch (err) {
      toast.error(err?.response?.data?.message || "Visual Save Failure");
    } finally {
      setUploading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;
    setSaving(true);
    const payload = {
      title: formData.title.trim(),
      couponCode: (formData.couponCode || "").trim().toUpperCase(),
      discountType: formData.discountType,
      discountValue: Number(formData.discountValue),
      applyTo: formData.applyTo,
      applyToCategory: formData.applyToCategory.trim(),
      applyToProductId: formData.applyToProductId || null,
      startDate: formData.startDate,
      endDate: formData.endDate,
      usageLimit: Number(formData.usageLimit || 0),
      perUserLimit: Number(formData.perUserLimit || 0),
      isActive: formData.isActive,
      image: formData.image,
      link: formData.link.trim(),
      description: formData.description.trim() || formData.title.trim(),
      minOrderAmount: Number(formData.minOrderAmount || 0),
      maxDiscount: formData.maxDiscount !== "" ? Number(formData.maxDiscount) : null,
    };

    try {
      if (editingId) {
        await api.put(`/admin/offers/${editingId}`, payload);
        toast.success("Order Updated");
      } else {
        await api.post("/admin/offers", payload);
        toast.success("Order Appended");
      }
      setFormOpen(false);
      fetchOffers();
    } catch (err) {
      toast.error(err?.response?.data?.message || "Save Failure");
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Terminate this marketing order?")) return;
    try {
      await api.delete(`/admin/offers/${id}`);
      toast.success("Order Deleted");
      fetchOffers();
    } catch {
      toast.error("Delete Failure");
    }
  };

  return (
    <div className="space-y-12">
      {/* Header */}
      <div className="flex justify-between items-end border-b border-gray-100 pb-6">
        <div className="space-y-2">
          <p className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-1">
             Marketing List
          </p>
          <h1 className="text-3xl md:text-4xl font-black text-[#0f172a] tracking-tighter uppercase leading-none">
             Offers
          </h1>
        </div>

        <Button
          variant="primary"
          onClick={openCreate}
        >
          <Plus size={18} strokeWidth={3} />
          Add Offer
        </Button>
      </div>

      {/* Control Strip */}
      <div className="flex flex-col sm:flex-row gap-3 items-center justify-between bg-[#f1f5f9] p-3 rounded-xl border border-gray-100 shadow-inner">
         <div className="flex items-center gap-3 px-2">
            <div className="flex items-center gap-2 text-[9px] font-black text-gray-400 uppercase tracking-widest">
               <Tag size={14} className="text-[#1e3a8a]" /> {offers.length} Active Campaigns
            </div>
            <div className="flex items-center gap-2 text-[9px] font-black text-[#0f172a] uppercase tracking-widest">
               <Sparkles size={14} className="text-[#1e3a8a]" /> High-Conversion
            </div>
         </div>

         <div className="flex items-center gap-2 px-2">
            <Activity size={14} className="text-[#1e3a8a]" />
            <span className="text-[9px] font-black uppercase tracking-widest text-[#0f172a]">Update Monitor Live</span>
         </div>
      </div>

      {/* Table-style Listing */}
      <div className="bg-white rounded-xl border border-gray-100 overflow-hidden shadow-sm">
        {loading ? (
          <div className="p-10 space-y-4 ">
            {[...Array(3)].map((_, i) => (
              <div key={i} className="h-16 bg-[#f1f5f9] rounded-lg" />
            ))}
          </div>
        ) : offers.length === 0 ? (
          <div className="py-24 text-center bg-[#f1f5f9] rounded-xl border border-dashed border-gray-200">
             <p className="text-xs font-black uppercase tracking-widest text-gray-300">No records found. No active marketing logics.</p>
          </div>
        ) : (
          <div className="divide-y divide-gray-50">
            {offers?.map((off) => {
              const s = off.status || "OFF";
              const isExpired = s === "EXPIRED";
              const isLimitReached = s === "LIMIT ENDED";
              const isComing = s === "COMING";
              const isActive = s === "ACTIVE";

              return (
                <div
                  key={off.id}
                  className={`flex items-center justify-between p-4 transition-all group border-b border-gray-50 last:border-0 ${
                    isExpired ? "opacity-60 bg-gray-50/50" : 
                    isLimitReached ? "bg-red-50/30 border-l-4 border-l-red-500" : 
                    "hover:bg-[#f1f5f9]"
                  }`}
                >
                  {/* Left */}
                  <div className="flex items-center gap-4">
                    <div className="relative">
                      <img
                        src={off.image || "https://images.unsplash.com/photo-1607082348824-0a96f2a4b9da?q=80&w=400&auto=format&fit=crop"}
                        className={`w-20 h-14 object-cover rounded-xl ring-1 ring-gray-100 transition-all ${!isExpired ? 'group-hover:ring-[#1e3a8a]' : 'grayscale'}`}
                      />

                      {/* Dynamic Badge Engine */}
                      <div className="absolute -top-2 -right-2 transform scale-90">
                        {isComing && (
                          <div className="bg-amber-100 text-amber-700 border border-amber-200 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm flex items-center gap-1">
                            <div className="w-1 h-1 bg-amber-500 rounded-full animate-pulse" /> COMING
                          </div>
                        )}
                        {isActive && (
                          <div className="bg-green-100 text-green-700 border border-green-200 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm flex items-center gap-1">
                            <div className="w-1 h-1 bg-green-500 rounded-full animate-pulse" /> LIVE
                          </div>
                        )}
                        {isExpired && (
                          <div className="bg-gray-200 text-gray-600 border border-gray-300 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm">
                            EXPIRED
                          </div>
                        )}
                        {isLimitReached && (
                          <div className="bg-red-100 text-red-700 border border-red-200 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm">
                            LIMIT ENDED
                          </div>
                        )}
                        {s === "OFF" && (
                          <div className="bg-gray-100 text-gray-400 border border-gray-200 px-2 py-0.5 rounded-full text-[8px] font-black uppercase tracking-widest shadow-sm">
                            DISABLED
                          </div>
                        )}
                      </div>
                    </div>

                    <div className="space-y-1">
                      <p className={`text-sm font-black uppercase tracking-tight transition-colors ${isExpired ? 'text-gray-400' : 'text-[#0f172a] group-hover:text-[#1e3a8a]'}`}>
                        {off?.title || "Untitled Campaign"}
                      </p>
                      <div className="flex items-center gap-3">
                        <div className="flex items-center gap-1.5 text-[9px] font-black text-gray-400 uppercase tracking-widest">
                           <ShieldCheck size={10} className="text-[#1e3a8a]" /> {(off?.couponCode || "").toUpperCase()}
                        </div>
                        <div className="h-3 w-[1px] bg-gray-200" />
                        <div className={`flex items-center gap-1.5 text-[9px] font-black uppercase tracking-widest ${isLimitReached ? 'text-red-500' : 'text-gray-400'}`}>
                           <Users size={10} /> {off.usedCount} / {off.usageLimit || "∞"} USED
                        </div>
                      </div>
                    </div>
                  </div>

                  {/* Actions */}
                  <div className="flex items-center gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                    <Button variant="icon" onClick={() => openEdit(off)}>
                      <Edit2 size={16} />
                    </Button>
                    <Button variant="icon" onClick={() => handleDelete(off.id)}>
                      <Trash2 size={16} className="text-red-400" />
                    </Button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {/* FULL SCREEN MODAL FORM */}
      {formOpen && (
        <div className="fixed inset-0 z-[100] bg-white overflow-y-auto animate-in fade-in duration-500">
          <div className="max-w-[1200px] mx-auto p-3 md:p-12">

            {/* Modal Header */}
            <div className="flex items-center justify-between mb-12 border-b border-gray-100 pb-6">
               <div className="space-y-1">
                  <h2 className="text-2xl md:text-3xl font-black text-[#0f172a] tracking-tighter uppercase">
                    {editingId ? "Edit Campaign" : "New Offer"}
                  </h2>
               </div>

               <Button 
                variant="icon"
                onClick={() => setFormOpen(false)}
               >
                 <X size={20} />
               </Button>
            </div>

            <form onSubmit={handleSubmit} className="grid grid-cols-1 lg:grid-cols-5 gap-8">

              {/* LEFT SIDE (FORM) */}
              <div className="lg:col-span-3 space-y-6">

                {/* SECTION 1: BASIC INFO */}
                <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                  <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Basic Info</h3>
                  <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Title *</label>
                      <input value={formData.title} onChange={(e) => updateField("title", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                    </div>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Coupon Code *</label>
                      <div className="flex gap-2">
                        <input value={formData.couponCode} onChange={(e) => updateField("couponCode", e.target.value.toUpperCase())} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                        <button type="button" onClick={generateCoupon} className="h-11 w-11 flex-shrink-0 flex items-center justify-center bg-gray-100 rounded-xl hover:bg-gray-200 text-gray-700 transition">
                          <RefreshCw size={16} />
                        </button>
                      </div>
                    </div>
                  </div>
                </div>

                {/* SECTION 2: OFFER DETAILS */}
                <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                  <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Offer Details</h3>
                  <div className="grid md:grid-cols-3 gap-4">
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Type</label>
                      <select value={formData.discountType} onChange={(e) => updateField("discountType", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500">
                        <option value="percentage">Percentage</option>
                        <option value="flat">Flat Value</option>
                      </select>
                    </div>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Value *</label>
                      <input type="number" min="0" value={formData.discountValue} onChange={(e) => updateField("discountValue", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                    </div>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Scope</label>
                      <select value={formData.applyTo} onChange={(e) => updateField("applyTo", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500">
                        <option value="all">Universal</option>
                        <option value="category">Category</option>
                        <option value="product">Product</option>
                      </select>
                    </div>
                  </div>
                  {formData.applyTo === "category" && (
                    <div className="mt-4">
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Category</label>
                      <input value={formData.applyToCategory} onChange={(e) => updateField("applyToCategory", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" placeholder="e.g. Men, Shoes..." />
                    </div>
                  )}
                </div>

                {/* SECTION 3: DATE RANGE */}
                <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                  <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Date Range</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Start Date</label>
                      <input type="date" value={formData.startDate} onChange={(e) => updateField("startDate", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                    </div>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">End Date</label>
                      <input type="date" value={formData.endDate} onChange={(e) => updateField("endDate", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" />
                    </div>
                  </div>
                </div>

                {/* SECTION 4: FINANCIAL SAFEGUARDS */}
                <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                  <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Financial Safeguards</h3>
                  <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Min Order Amount (₹)</label>
                      <input type="number" min="0" value={formData.minOrderAmount} onChange={(e) => updateField("minOrderAmount", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" placeholder="0 = no minimum" />
                    </div>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Max Discount (₹)</label>
                      <input type="number" min="0" value={formData.maxDiscount} onChange={(e) => updateField("maxDiscount", e.target.value)} disabled={formData.discountType === 'flat'} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500 disabled:opacity-50" placeholder="unlimited" />
                      {formData.discountType === 'flat' && <p className="text-[10px] text-gray-400 mt-1 uppercase font-bold tracking-tighter">Only for percentage types</p>}
                    </div>
                  </div>
                </div>

                {/* BUTTON SECTION */}
                <div className="flex gap-4 pt-4">
                   <button type="submit" disabled={saving} className="flex-1 bg-indigo-600 text-white py-3 rounded-xl font-semibold hover:bg-indigo-700 transition">
                     {saving ? "Saving..." : "Save Offer"}
                   </button>
                   <button type="button" onClick={() => setFormOpen(false)} className="flex-1 border border-gray-300 text-gray-700 py-3 rounded-xl hover:bg-gray-100 transition">
                      Cancel
                   </button>
                </div>
              </div>

              {/* RIGHT SIDE (MEDIA + USAGE) */}
              <div className="lg:col-span-2 space-y-6">

                 {/* MEDIA CARD */}
                 <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                    <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Media</h3>
                    {formData.image ? (
                       <div className="relative aspect-video rounded-xl overflow-hidden border border-gray-200">
                          <img src={formData.image} className="w-full h-full object-cover" />
                          <button type="button" onClick={() => updateField("image", "")} className="absolute top-2 right-2 h-8 w-8 bg-white/90 backdrop-blur-sm rounded-lg flex items-center justify-center text-red-500 hover:bg-red-500 hover:text-white transition shadow-sm">
                             <X size={16} strokeWidth={2.5} />
                          </button>
                       </div>
                    ) : (
                       <div
                         onClick={() => document.getElementById("offer-image-upload").click()}
                         className="border-2 border-dashed border-gray-300 rounded-xl p-8 text-center hover:border-indigo-500 cursor-pointer transition-colors"
                       >
                         <Sparkles className="text-gray-400 mx-auto mb-3" size={32} />
                         <p className="text-sm font-medium text-gray-600">Click to upload promotion image</p>
                         <input id="offer-image-upload" type="file" accept="image/*" className="hidden" onChange={(e) => handleImageUpload(e.target.files?.[0])} />
                       </div>
                    )}
                 </div>

                 {/* USAGE SECTION */}
                 <div className="bg-white rounded-xl p-5 shadow-sm space-y-4">
                    <h3 className="text-lg font-bold text-gray-800 border-b border-gray-100 pb-2 mb-4">Usage Limits</h3>
                    <div className="grid grid-cols-2 gap-3">
                      <div>
                        <label className="text-sm font-medium text-gray-600 mb-1 block">Limit</label>
                        <input type="number" min="0" value={formData.usageLimit} onChange={(e) => updateField("usageLimit", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" placeholder="0 = unlim" />
                      </div>
                      <div>
                        <label className="text-sm font-medium text-gray-600 mb-1 block">Per User</label>
                        <input type="number" min="0" value={formData.perUserLimit} onChange={(e) => updateField("perUserLimit", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-2.5 focus:outline-none focus:ring-2 focus:ring-indigo-500" placeholder="0 = unlim" />
                      </div>
                    </div>
                 </div>

                 {/* ACTIVE UPDATE (TEXTAREA CARD) */}
                 <div className="bg-white rounded-xl p-5 shadow-sm space-y-6">
                    <label className="flex items-center gap-3 cursor-pointer">
                        <input type="checkbox" className="w-5 h-5 rounded text-indigo-600 focus:ring-indigo-500" checked={formData.isActive} onChange={(e) => updateField("isActive", e.target.checked)} />
                        <span className="text-sm font-medium text-gray-800">Active Campaign</span>
                    </label>
                    <div>
                      <label className="text-sm font-medium text-gray-600 mb-1 block">Description</label>
                      <textarea rows={3} value={formData.description} onChange={(e) => updateField("description", e.target.value)} className="w-full bg-gray-100 rounded-xl px-4 py-3 focus:outline-none focus:ring-2 focus:ring-indigo-500" placeholder="Campaign details..." />
                    </div>
                 </div>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useEffect } from "react";
import { api } from "../../api/client";
import toast from "react-hot-toast";
import { ShoppingBag, Search, Filter, ShieldCheck, User as UserIcon, Zap, CheckCircle, Clock, Truck, XCircle } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";
import { mapOrder } from "../../api/dynamicMapper";

export default function Orders() {
  const [orders, setOrders] = useState([]);
  const [selectedOrder, setselectedOrder] = useState(null);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");
  const [processingPayment, setProcessingPayment] = useState(false);

  const fetchOrders = async () => {
    try {
      setLoading(true);
      const data = await api.get("/admin/orders");
      // Log removed for production
      const mapped = Array.isArray(data) ? data.map(mapOrder) : [];
      setOrders(mapped);
    } catch (err) {
      console.error("ORDERS FETCH ERROR:", err.response?.data || err.message);
      toast.error("Failed to sync orders manifest");
      setOrders([]);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchOrders();
    const interval = setInterval(fetchOrders, 10000);
    return () => clearInterval(interval);
  }, []);

  const updateStatus = async (id, status) => {
    // Log removed for production(`[Admin] Updating order ${id} to ${status}`);
    
    // Optimistic UI Update
    const previousOrders = [...orders];
    setOrders((prev) =>
      prev.map((o) => (o._id === id ? { ...o, status: status } : o))
    );

    try {
      await api.put(`/admin/orders/${id}/status`, {
        status: status,
      });
      toast.success(`Order ${status.toUpperCase()} Successfully`);
    } catch (err) {
      console.error("STATUS UPDATE ERROR:", err.response?.data || err.message);
      toast.error("Failed to update status");
      // Rollback on failure
      setOrders(previousOrders);
    }
  };

  const handleViewDetails = async (id) => {
    try {
      toast.loading("Fetching Order Manifest...", { id: "viewing" });
      const data = await api.get(`/orders/${id}`);
      setselectedOrder(mapOrder(data?.data || data));
      toast.success("Details Loaded", { id: "viewing" });
    } catch (err) {
      console.error("VIEW ERROR:", err);
      toast.error("Failed to load full manifest", { id: "viewing" });
    }
  };

  const handleDownloadInvoice = async (orderId) => {
    try {
      toast.loading("Generating Professional Invoice...", { id: "downloading" });
      const res = await api.get(`/orders/${orderId}/invoice?t=${Date.now()}`, {
        responseType: "blob",
      });
      
      // Step 3 fix: Precise blob-to-PDF download
      const url = window.URL.createObjectURL(new Blob([res], { type: "application/pdf" }));
      const link = document.createElement("a");
      link.href = url;
      link.setAttribute("download", `invoice-${orderId.slice(-8).toUpperCase()}.pdf`);
      document.body.appendChild(link);
      link.click();
      
      // Cleanup
      document.body.removeChild(link);
      window.URL.revokeObjectURL(url);
      
      toast.success("Invoice Downloaded Successfully", { id: "downloading" });
    } catch (err) {
      let message = "Failed to generate or download invoice.";
      
      // Axios error handling for Blobs
      if (err.response?.data instanceof Blob) {
        try {
          const text = await err.response.data.text();
          const errorData = JSON.parse(text);
          message = errorData.message || message;
        } catch (decodeErr) {
          console.error("Failed to decode error blob:", decodeErr);
        }
      } else if (err.message) {
        message = err.message;
      }
      
      console.error("Download Error Details:", err);
      toast.error(message, { id: "downloading" });
    }
  };

  const handleUpdatePaymentStatus = async (id, status) => {
    if (status !== "PAID") return; // We only handle marking as paid via this specific button
    
    // Optimistic UI Update
    const previousOrders = [...orders];
    setOrders(prev => prev.map(o => o.id === id ? { ...o, paymentStatus: "PAID" } : o));
    if (selectedOrder?.id === id) setselectedOrder({ ...selectedOrder, paymentStatus: "PAID" });

    try {
      setProcessingPayment(true);
      toast.loading("Verifying Transaction...", { id: "payment" });
      
      const res = await api.patch(`/admin/orders/${id}/paid`);
      
      // Sync with server response
      const updatedOrder = mapOrder(res.data || res);
      setOrders(prev => prev.map(o => o.id === id ? updatedOrder : o));
      if (selectedOrder?.id === id) setselectedOrder(updatedOrder);
      
      toast.success("Payment Verified Instantly", { id: "payment" });
    } catch (err) {
      console.error("PAYMENT VERIFICATION ERROR:", err);
      toast.error(err.response?.data?.message || "Verification failed", { id: "payment" });
      // Rollback on failure
      setOrders(previousOrders);
    } finally {
      setProcessingPayment(false);
    }
  };

  const statusStyles = (status) => {
    const s = String(status || "").toLowerCase();
    if (s === "delivered") return "bg-green-100 text-green-700 border-green-200";
    if (s === "shipped") return "bg-blue-100 text-blue-700 border-blue-200";
    if (s === "confirmed") return "bg-indigo-100 text-indigo-700 border-indigo-200";
    if (s === "placed") return "bg-gray-100 text-gray-700 border-gray-200";
    if (s === "cancelled") return "bg-red-100 text-red-700 border-red-200";
    return "bg-gray-100 text-gray-700";
  };

  const filteredOrders = Array.isArray(orders) ? orders.filter(o => 
    o._id?.toLowerCase().includes(search.toLowerCase()) || 
    o.user?.name?.toLowerCase().includes(search.toLowerCase()) ||
    o.products?.[0]?.title?.toLowerCase().includes(search.toLowerCase())
  ) : [];

  return (
    <div className="max-w-7xl mx-auto space-y-6">
      {/* HEADER SECTION */}
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 border-b pb-6">
        <div>
          <div className="flex items-center gap-2 mb-1">
             <ShoppingBag size={18} className="text-gray-900" />
             <span className="text-xs font-bold text-gray-400 uppercase tracking-widest">Purchase management</span>
          </div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight uppercase">Purchases</h1>
        </div>

        <div className="flex items-center gap-3">
          <div className="bg-white px-4 py-2 rounded-xl shadow-sm border flex items-center gap-2">
            <div className="h-2 w-2 rounded-full bg-green-500 animate-pulse" />
            <span className="text-[10px] font-black uppercase tracking-widest text-gray-500">System Live</span>
          </div>
        </div>
      </div>

      {/* FILTER & SEARCH BAR */}
      <div className="flex flex-col lg:flex-row gap-4 items-center justify-between bg-white p-4 rounded-xl shadow-sm border border-gray-100">
        <div className="relative w-full lg:w-96">
          <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-gray-400" size={16} />
          <input
            placeholder="Search purchase ID, customer, items..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-10 pr-4 py-2.5 rounded-lg bg-gray-50 border border-gray-200 text-sm focus:bg-white focus:border-gray-900 outline-none transition-all"
          />
        </div>
        
        <div className="flex items-center gap-6">
           <div className="flex items-center gap-2 text-xs font-bold text-gray-400 uppercase tracking-widest">
              <Zap size={14} className="text-indigo-500" /> {filteredOrders.length} Total Records
           </div>
           <button className="flex items-center gap-2 text-xs font-bold text-gray-900 hover:text-indigo-600 uppercase tracking-widest transition-all">
              <Filter size={14} /> Filter Reports
           </button>
        </div>
      </div>

      {/* ORDERS TABLE */}
      <div className="bg-white rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        {loading ? (
          <div className="p-8 space-y-4">
            {[1,2,3,4,5].map((i) => (
              <div key={i} className="h-16 bg-gray-50 rounded-xl animate-pulse" />
            ))}
          </div>
        ) : (
          <div className="overflow-x-auto">
            <table className="w-full border-collapse">
               <thead>
                  <tr className="bg-gray-50/50 border-b">
                     <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-wider">Order ID</th>
                     <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-wider">Product</th>
                     <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-wider">Customer</th>
                     <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-wider">Payment</th>
                     <th className="px-6 py-4 text-left text-[10px] font-bold text-gray-400 uppercase tracking-wider">Status</th>
                     <th className="px-6 py-4 text-right text-[10px] font-bold text-gray-400 uppercase tracking-wider">Actions</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-gray-50">
                  {/* TASK 3: SAFE RENDER GUARD */}
                  {Array.isArray(filteredOrders) && filteredOrders.length > 0 ? (
                    filteredOrders.map((order) => (
                       <tr key={order.id} className="hover:bg-gray-50/50 transition-colors group">
                        {/* ID */}
                        <td className="px-6 py-4">
                           <span className="text-xs font-black text-gray-900 uppercase">
                             #{order.id?.slice(-6).toUpperCase()}
                           </span>
                           <p className="text-[10px] text-gray-400 font-medium">
                             {new Date(order.createdAt).toLocaleDateString()}
                           </p>
                        </td>

                        {/* PRODUCT COLUMN */}
                        <td className="px-6 py-4">
                          <div className="flex items-center gap-3">
                            <img
                              src={order.products?.[0]?.image || '/placeholder.png'}
                              className="w-10 h-10 rounded-lg object-cover border bg-white shadow-sm"
                            />
                            <div className="max-w-[150px]">
                              <p className="text-sm font-bold text-gray-800 truncate">
                                {order.products?.[0]?.title || "Product"}
                              </p>
                              <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">
                                Qty: {order.products?.[0]?.quantity || 1}
                              </p>
                            </div>
                          </div>
                        </td>

                        {/* ADDRESS COLUMN */}
                        <td className="px-6 py-4">
                          <div className="text-[11px] text-gray-600 max-w-[200px] leading-relaxed">
                            <span className="font-black text-gray-900 block truncate uppercase">{order.user?.name}</span>
                            <span className="truncate block opacity-80 italic">{order.address?.city ? `${order.address.city}, ${order.address.state || ''}` : typeof order.address === 'string' ? order.address : "No address"}</span>
                          </div>
                        </td>

                        {/* PAYMENT COLUMN */}
                        <td className="px-6 py-4">
                          {order.paymentMethod === "COD" || order.paymentMethod === "cod" ? (
                            <span className="text-[10px] font-bold px-2 py-1 rounded-full bg-orange-50 text-orange-600 border border-orange-100 uppercase tracking-tighter">
                              COD
                            </span>
                          ) : (
                            <span className="text-[10px] font-bold px-2 py-1 rounded-full bg-indigo-50 text-indigo-600 border border-indigo-100 uppercase tracking-tighter">
                              Online
                            </span>
                          )}
                          <div className="flex items-center gap-2 mt-1.5">
                            <span className={`px-2 py-0.5 rounded-md text-[9px] font-black tracking-tight uppercase shadow-sm ${
                              (order.paymentStatus || "").toUpperCase() === "PAID" 
                                ? "bg-emerald-100 text-emerald-700 border border-emerald-200" 
                                : (order.paymentStatus || "").toUpperCase() === "FAILED"
                                ? "bg-rose-100 text-rose-700 border border-rose-200"
                                : "bg-amber-100 text-amber-700 border border-amber-200"
                            }`}>
                              {order.paymentStatus || "PENDING"}
                            </span>
                            <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest italic leading-none truncate">
                              ₹{order.totalAmount || 0}
                            </span>
                          </div>
                        </td>

                        {/* STATUS */}
                        <td className="px-6 py-4">
                          <span className={`px-2.5 py-1 rounded-lg text-[10px] font-bold uppercase tracking-wider border ${statusStyles(order.status)}`}>
                            {order.status}
                          </span>
                        </td>

                        {/* VIEW BUTTON */}
                        <td className="px-6 py-4 text-right">
                          <div className="flex items-center justify-end gap-2">
                            <select
                              value={order.status}
                              onChange={(e) => {
                                const newStatus = e.target.value;
                                updateStatus(order.id, newStatus);
                              }}
                              className="px-2 py-1.5 text-[10px] font-bold rounded-lg bg-white border border-gray-200 outline-none hover:border-gray-900 focus:ring-2 focus:ring-indigo-500 transition-all shadow-sm cursor-pointer"
                            >
                              <option value="placed">PLACED</option>
                              <option value="confirmed">CONFIRMED</option>
                              <option value="shipped">SHIPPED</option>
                              <option value="delivered">DELIVERED</option>
                              <option value="cancelled">CANCELLED</option>
                            </select>
                            <button
                              onClick={() => handleViewDetails(order.id)}
                              className="text-[10px] font-black uppercase tracking-widest px-3 py-2 rounded-lg bg-gray-900 text-white hover:bg-gray-800 shadow-sm transition-all"
                            >
                              View
                            </button>
                          </div>
                        </td>
                      </tr>
                    ))
                  ) : (
                    <tr>
                      <td colSpan={6} className="py-24 text-center">
                        <div className="flex flex-col items-center gap-3">
                          <ShieldCheck size={48} className="text-gray-100" strokeWidth={1} />
                          <p className="text-sm font-black uppercase tracking-widest text-gray-300">No Order Found</p>
                        </div>
                      </td>
                    </tr>
                  )}
               </tbody>
            </table>
          </div>
        )}
      </div>

      {/* STEP 8: ORDER DETAILS DRAWER */}
      <AnimatePresence>
        {selectedOrder && (
          <div className="fixed inset-0 z-50 overflow-hidden">
            <div 
              className="absolute inset-0 bg-gray-900/40 backdrop-blur-sm"
              onClick={() => setselectedOrder(null)}
            />
            
            <div className="absolute inset-y-0 right-0 max-w-md w-full bg-white shadow-2xl flex flex-col transform transition-transform duration-300">
              {/* DRAWER HEADER */}
              <div className="p-6 border-b flex items-center justify-between bg-gray-50">
                <div>
                  <h2 className="text-xl font-black text-gray-900 uppercase">Order Details</h2>
                  <p className="text-xs font-bold text-gray-400 mt-1 uppercase tracking-widest">ID: {selectedOrder.id}</p>
                </div>
                <button 
                  onClick={() => setselectedOrder(null)}
                  className="p-2 hover:bg-white rounded-full transition-colors border border-transparent hover:border-gray-200"
                >
                  <XCircle size={24} className="text-gray-400" />
                </button>
              </div>

              <div className="flex-1 overflow-y-auto p-6 space-y-8 no-scrollbar">
                {/* STEP 9: PRODUCTS LIST */}
                <section>
                  <h3 className="text-xs font-black text-gray-300 uppercase tracking-widest mb-4">Product Manifest</h3>
                  <div className="space-y-4">
                    {(selectedOrder.products || []).map((item, i) => (
                      <div key={i} className="flex gap-4 p-3 rounded-xl border border-gray-100 bg-gray-50/30">
                        <img 
                          src={item.image || "/placeholder.png"} 
                          className="w-16 h-16 rounded-xl object-cover border bg-white shadow-sm" 
                        />
                        <div className="flex-1">
                          <p className="text-sm font-bold text-gray-900">
                            {item.title || "Product"}
                          </p>
                          <div className="flex items-center justify-between mt-1">
                            <span className="text-[10px] text-gray-400 uppercase font-black tracking-widest">Qty: {item.quantity}</span>
                            <div className="flex flex-col items-end">
                               {item.topSize && item.bottomSize ? (
                                 <span className="text-[9px] font-black text-indigo-600 uppercase">Size: {item.topSize}(T) / {item.bottomSize}(B)</span>
                               ) : item.size ? (
                                 <span className="text-[9px] font-black text-indigo-600 uppercase">Size: {item.size}</span>
                               ) : null}
                               <span className="text-sm font-black text-indigo-600">₹{item.price}</span>
                            </div>
                          </div>
                        </div>
                      </div>
                    ))}
                  </div>
                </section>

                {/* STEP 10: FULL ADDRESS */}
                <section>
                  <h3 className="text-xs font-black text-gray-300 uppercase tracking-widest mb-4">Shipping Destination</h3>
                  <div className="p-4 rounded-xl border border-gray-100 bg-indigo-50/30">
                    <p className="text-sm font-bold text-gray-900 mb-2">
                       {selectedOrder.shippingAddress?.name || selectedOrder.user?.name || "N/A"}
                    </p>
                    <p className="text-xs text-gray-600 leading-relaxed font-medium">
                      {selectedOrder.shippingAddress ? 
                        `${selectedOrder.shippingAddress.address}, ${selectedOrder.shippingAddress.city}, ${selectedOrder.shippingAddress.state} - ${selectedOrder.shippingAddress.pincode}` : 
                        typeof selectedOrder.address === 'string' ? selectedOrder.address : "No address provided"
                      }<br />
                      <span className="font-bold text-gray-900 italic opacity-60">Status verified via metadata</span>
                    </p>
                    <div className="mt-4 pt-4 border-t border-gray-200/50">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Contact Module</p>
                      <p className="text-sm font-bold text-gray-900">
                        Phone: {selectedOrder.shippingAddress?.phone || selectedOrder.phone || "N/A"}
                      </p>
                    </div>
                  </div>
                </section>

                {/* STEP 11: PAYMENT INFO */}
                <section>
                  <h3 className="text-xs font-black text-gray-300 uppercase tracking-widest mb-4">Fiscal Logic</h3>
                  <div className="grid grid-cols-2 gap-3">
                    <div className="p-3 rounded-xl border border-gray-100">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Method</p>
                      <span className="text-xs font-bold text-gray-900">{selectedOrder.paymentMethod}</span>
                    </div>
                    <div className="p-3 rounded-xl border border-gray-100 flex-1">
                      <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest mb-1">Status</p>
                      <span className={`text-[10px] font-black px-2 py-0.5 rounded-md uppercase ${(selectedOrder.paymentStatus || "").toUpperCase() === "PAID" ? "bg-emerald-100 text-emerald-700" : "bg-amber-100 text-amber-700"}`}>
                        {selectedOrder.paymentStatus || "PENDING"}
                      </span>
                    </div>
                  </div>
                </section>

                {/* STEP 12: TOTAL */}
                <section className="p-6 bg-gray-900 rounded-2xl text-white shadow-xl">
                   <div className="flex justify-between items-center mb-2 opacity-60">
                      <span className="text-[10px] font-black uppercase tracking-widest">Order Valuation</span>
                      <span className="text-sm font-bold">₹{selectedOrder.totalAmount}</span>
                   </div>
                   <div className="flex justify-between items-center">
                      <span className="text-xs font-black uppercase tracking-widest">Grand Total</span>
                      <span className="text-2xl font-black italic tracking-tighter">₹{selectedOrder.totalAmount}</span>
                   </div>
                </section>
              </div>

              {/* ACTION FOOTER */}
              <div className="p-6 border-t bg-gray-50 space-y-3">
                 { (selectedOrder.paymentStatus || "").toUpperCase() !== "PAID" && (
                   <button 
                    disabled={processingPayment}
                    onClick={() => handleUpdatePaymentStatus(selectedOrder.id, "PAID")}
                    className="w-full py-4 bg-emerald-600 hover:bg-emerald-500 text-white font-black text-xs uppercase tracking-widest rounded-xl transition-all shadow-lg active:scale-95 flex items-center justify-center gap-2 disabled:opacity-50"
                   >
                     <ShieldCheck size={16} /> {processingPayment ? "Processing..." : "Verify & Mark as PAID"}
                   </button>
                 )}
                 <div className="flex gap-3">
                    <button 
                      onClick={() => setselectedOrder(null)}
                      className="flex-1 py-3 rounded-xl border border-gray-200 text-xs font-black uppercase tracking-widest text-gray-400 hover:bg-white hover:text-gray-900 transition-all"
                    >
                      Close Manifest
                    </button>
                    <button 
                      onClick={() => handleDownloadInvoice(selectedOrder.id)}
                      className="flex-1 py-3 rounded-xl bg-indigo-600 text-white text-xs font-black uppercase tracking-widest shadow-md hover:bg-indigo-700 transition-all flex items-center justify-center gap-2"
                    >
                      <Clock size={14} className="animate-pulse" /> Download Invoice
                    </button>
                 </div>
              </div>
            </div>
          </div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useMemo, useState, useEffect } from "react";
import { api } from "../../api/client";
import { mapProduct } from "../../api/dynamicMapper";
import { uploadMultipleImages, uploadProductVideo } from "../../api/upload";
import { Plus, Edit2, Trash2, Search as SearchIcon, Sparkles, UploadCloud, X, RefreshCw, Package, ArrowRight, Image as ImageIcon, Layers, Tag as TagIcon, Layout, Info, ShieldCheck, Zap, ChevronDown } from "lucide-react";
import toast from "react-hot-toast";
import { motion, AnimatePresence } from "framer-motion";
import Button from "../../components/ui/Button";
import { categoryData } from "../constants/categoryData";

const defaultForm = {
  title: "",
  brand: "",
  category: "MEN",
  subcategory: "",
  productType: "",
  type: "TOPWEAR",
  originalPrice: "",
  discountPrice: "",
  stock: "",
  sku: "",
  shortDescription: "",
  fullDescription: "",
  featured: false,
  trending: false,
  images: [],
  video: "",
  sizes: [],
  topSizes: [],
  bottomSizes: [],
};

const formatPrice = (p) => Number(p || 0).toLocaleString("en-IN", { style: "currency", currency: "INR", maximumFractionDigits: 0 });

export default function Products() {
  const [products, setProducts] = useState([]);
  const [filtered, setFiltered] = useState([]);
  const [search, setSearch] = useState("");
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [uploading, setUploading] = useState(false);
  const [formOpen, setFormOpen] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [dragOver, setDragOver] = useState(false);
  const [selectedFiles, setSelectedFiles] = useState([]);
  const [videoFile, setVideoFile] = useState(null);
  const [videoUploading, setVideoUploading] = useState(false);
  const [errors, setErrors] = useState({});
  const [formData, setFormData] = useState(defaultForm);
  const [imagePreviews, setImagePreviews] = useState([]);
  const [videoPreview, setVideoPreview] = useState(null);
  const [meta, setMeta] = useState({ page: 1, totalPages: 1 });
  const [currentPage, setCurrentPage] = useState(1);

  // Auto-revoke Object URLs to prevent memory leaks
  useEffect(() => {
    return () => {
      imagePreviews.forEach(URL.revokeObjectURL);
      if (videoPreview) URL.revokeObjectURL(videoPreview);
    };
  }, [imagePreviews, videoPreview]);

  const fetchProducts = async (page = 1) => {
    try {
      setLoading(true);
      const res = await api.get(`/admin/products?page=${page}&limit=20&q=${search}`);
      const data = res?.data || res || {};
      const list = Array.isArray(data.data) ? data.data : (Array.isArray(data) ? data : []);

      setProducts(list.map(mapProduct));
      setFiltered(list.map(mapProduct));
      setMeta({
        page: data.meta?.page || 1,
        totalPages: data.meta?.totalPages || 1
      });
      setCurrentPage(page);
    } catch {
      toast.error("Error loading: Catalog Access");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    const timer = setTimeout(() => {
      fetchProducts(1);
    }, 400);
    return () => clearTimeout(timer);
  }, [search]);

  const handleDelete = async (id) => {
    if (!window.confirm("Authorize permanent product erasure?")) return;
    try {
      await api.delete(`/admin/products/${id}`);
      toast.success("Product Deleted");
      fetchProducts(currentPage);
    } catch {
      toast.error("Erasure Order Failure");
    }
  };

  const discountPercent = useMemo(() => {
    const original = Number(formData.originalPrice || 0);
    const discount = Number(formData.discountPrice || 0);
    if (!original || !discount || discount >= original) return 0;
    return Math.round(((original - discount) / original) * 100);
  }, [formData.originalPrice, formData.discountPrice]);

  const previewImage = formData.images[0] || "https://images.unsplash.com/photo-1591047139829-d91aecb6caea?q=80&w=436&auto=format&fit=crop";
  const finalPrice = Number(formData.discountPrice || 0) > 0 ? Number(formData.discountPrice) : Number(formData.originalPrice || 0);

  const updateField = (key, value) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
    setErrors((prev) => ({ ...prev, [key]: "" }));
  };

  const openCreate = () => {
    setEditingId(null);
    setSelectedFiles([]);
    setVideoFile(null);
    setErrors({});
    setFormData(defaultForm);
    setImagePreviews([]);
    setVideoPreview(null);
    setFormOpen(true);
  };

  const openEdit = (prod) => {
    setEditingId(prod.id);
    setSelectedFiles([]);
    setVideoFile(null);
    setErrors({});
    setFormData({
      title: prod.title || "",
      brand: prod.brand || "",
      category: String(prod.category || "MEN").toUpperCase(),
      subcategory: prod.subcategory || "",
      productType: prod.productType || "",
      type: String(prod.type || "TOPWEAR").toUpperCase(),
      originalPrice: prod.originalPrice ?? prod.price ?? "",
      discountPrice: prod.discountPrice ?? "",
      stock: prod.stock ?? 0,
      sku: prod.sku || "",
      shortDescription: prod.shortDescription || "",
      fullDescription: prod.fullDescription || prod.description || "",
      featured: Boolean(prod.featured),
      trending: Boolean(prod.trending),
      images: Array.isArray(prod.images) ? prod.images : (prod.image ? [prod.image] : []),
      video: prod.video || "",
      sizes: Array.isArray(prod.sizes) ? prod.sizes : [],
      topSizes: Array.isArray(prod.topSizes) ? prod.topSizes : [],
      bottomSizes: Array.isArray(prod.bottomSizes) ? prod.bottomSizes : [],
    });
    setFormOpen(true);
  };

  const validateForm = () => {
    const next = {};
    if (!String(formData.title || "").trim()) next.title = "Name is required for protocol";
    if (!formData.category) next.category = "Category allocation required";
    if (!formData.subcategory) next.subcategory = "Subcategory required";
    if (!formData.productType) next.productType = "Product Type required";
    if (!formData.originalPrice || Number(formData.originalPrice) < 0) next.originalPrice = "Financial value required";
    if (!String(formData.fullDescription || formData.description || "").trim()) next.fullDescription = "Data manifest/description required";

    if (formData.type === "FULL_OUTFIT") {
      if (!formData.topSizes || formData.topSizes.length === 0) next.topSizes = "Top dimensions missing";
      if (!formData.bottomSizes || formData.bottomSizes.length === 0) next.bottomSizes = "Bottom dimensions missing";
    } else {
      if (!formData.sizes || formData.sizes.length === 0) next.sizes = "Standard sizing required";
    }

    if (formData.images.length === 0) next.images = "Visual nodes/images required";

    setErrors(next);
    if (Object.keys(next).length > 0) {
      toast.error("Validation failure. Check protocol fields.");
      return false;
    }
    return true;
  };

  const generateSku = () => {
    const base = `${formData.category || "GEN"}-${formData.title || "ITEM"}`
      .replace(/\s+/g, "-")
      .replace(/[^a-zA-Z0-9-]/g, "")
      .toUpperCase()
      .slice(0, 16);
    const suffix = Math.random().toString(36).slice(2, 6).toUpperCase();
    updateField("sku", `${base}-${suffix}`);
  };

  const onPickFiles = (files) => {
    const fileList = Array.from(files || []);
    setSelectedFiles(fileList);

    // Generate previews
    const previews = fileList.map(file => URL.createObjectURL(file));
    setImagePreviews(previews);
  };

  const onPickVideo = (file) => {
    if (!file) return;
    setVideoFile(file);
    setVideoPreview(URL.createObjectURL(file));
  };

  const removeImage = (index) => {
    setFormData((prev) => ({ ...prev, images: prev.images.filter((_, i) => i !== index) }));
  };

  const handleUploadImages = async () => {
    if (!selectedFiles.length) return toast.error("Visual nodes required");
    setUploading(true);
    try {
      const urls = await uploadMultipleImages(selectedFiles);
      updateField("images", [...formData.images, ...urls]);
      setSelectedFiles([]);
      toast.success("Images uploaded");
    } catch (err) {
      toast.error(err?.response?.data?.message || "Save Order Failure");
    } finally {
      setUploading(false);
    }
  };

  const handleUploadVideo = async () => {
    if (!videoFile) return toast.error("Choose a video first");
    setVideoUploading(true);
    try {
      const url = await uploadProductVideo(videoFile);
      updateField("video", url);
      setVideoFile(null);
      setVideoPreview(null);
      toast.success("Video uploaded");
    } catch (err) {
      toast.error(err?.response?.data?.message || "Video upload failed");
    } finally {
      setVideoUploading(false);
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!validateForm()) return;

    setSaving(true);
    try {
      const payload = {
        title: formData.title.trim(),
        brand: formData.brand.trim(),
        category: String(formData.category || "MEN").trim().toUpperCase(),
        subcategory: formData.subcategory.trim(),
        productType: formData.productType.trim(),
        type: String(formData.type || "TOPWEAR").trim().toUpperCase(),
        originalPrice: Number(formData.originalPrice || 0),
        discountPrice: Number(formData.discountPrice || 0),
        price: Number(formData.discountPrice || 0) > 0 ? Number(formData.discountPrice) : Number(formData.originalPrice),
        stock: Number(formData.stock || 0),
        sku: formData.sku.trim(),
        shortDescription: formData.shortDescription.trim(),
        fullDescription: formData.fullDescription.trim(),
        description: formData.fullDescription.trim() || formData.shortDescription.trim(),
        featured: formData.featured,
        trending: formData.trending,
        images: formData.images,
        video: formData.video || "",
        sizes: formData.sizes,
        topSizes: formData.topSizes,
        bottomSizes: formData.bottomSizes,
      };

      if (editingId) {
        await api.put(`/admin/products/${editingId}`, payload);
        toast.success("Product Updated");
      } else {
        await api.post("/admin/products", payload);
        toast.success("Product Created");
      }
      setFormOpen(false);
      fetchProducts();
    } catch (err) {
      toast.error(err?.response?.data?.message || "Transmission Failure");
    } finally {
      setSaving(false);
    }
  };

  return (
    <div className="space-y-10">
      {/* HEADER PROTOCOL */}
      <div className="flex justify-between items-end border-b border-[#F2F2F2] pb-6">
        <div className="space-y-2">
          <p className="text-[9px] font-black text-gray-300 uppercase tracking-widest ml-1">
            Inventory
          </p>
          <h1 className="text-3xl md:text-4xl font-black text-[#0f172a] tracking-tighter uppercase leading-none">
             Item catalog
          </h1>
        </div>

        <Button
          variant="primary"
          onClick={openCreate}
        >
          <Plus size={18} strokeWidth={3} /> Add item
        </Button>
      </div>

      {/* COMMAND INTERFACE */}
      <div className="flex flex-col lg:flex-row gap-3 items-center justify-between bg-[#f1f5f9] p-3 rounded-xl border border-[#F2F2F2]">
        <div className="relative w-full lg:w-[400px] group">
          <SearchIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
          <input
            placeholder="Search items..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
            className="w-full pl-12 pr-4 py-3 rounded-lg bg-white border border-transparent text-[#0f172a] font-black uppercase tracking-widest text-[10px] focus:border-[#1e3a8a] outline-none transition-all shadow-sm"
          />
        </div>

        <div className="flex items-center gap-5 px-4">
           <div className="flex items-center gap-2 text-[9px] font-black text-gray-400 uppercase tracking-widest">
              <Package size={14} className="text-[#1e3a8a]" /> {products.length} Items
           </div>
           <div className="flex items-center gap-2 text-[9px] font-black text-gray-400 uppercase tracking-widest">
              <Sparkles size={14} className="text-[#1e3a8a]" /> Registry: OK
           </div>
        </div>
      </div>

      {/* MANIFEST GRID */}
      {loading ? (
        <div className="grid grid-cols-2 lg:grid-cols-4 gap-3">
          {[1,2,3,4,5,6,7,8].map((i) => (
            <div key={i} className="aspect-[3/4] bg-[#f1f5f9] border border-[#F2F2F2] rounded-xl " />
          ))}
        </div>
      ) : filtered.length === 0 ? (
        <div className="py-24 text-center bg-[#f1f5f9] rounded-xl border border-dashed border-gray-200">
           <p className="text-[11px] font-black uppercase tracking-widest text-gray-400">No results found. No products localized.</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
          {filtered.map((prod) => (
            <div
              key={prod.id}
              className="bg-white border border-[#F2F2F2] rounded-xl overflow-hidden shadow-sm hover:border-[#1e3a8a]/30 hover:shadow-md transition-all flex flex-col group"
            >
              <div className="aspect-[4/5] overflow-hidden relative">
                <img src={prod.image} className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-105" alt={prod.title} />

                {/* STOCK BADGE */}
                <div className="absolute top-3 left-3 z-10 bg-[#0f172a]/85 backdrop-blur-md text-white px-2 py-1 rounded-md font-black text-[7px] uppercase tracking-widest">
                  STK: {prod.stock}
                </div>

                {/* ADMIN ACTIONS OVERLAY - ALWAYS VISIBLE */}
                <div className="absolute inset-0 z-20 flex flex-col justify-end p-3 bg-gradient-to-t from-[#0f172a]/60 to-transparent">
                   <div className="flex gap-2">
                      <button 
                        onClick={() => openEdit(prod)}
                        className="flex-1 h-9 bg-white text-[#0f172a] rounded-lg text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-indigo-50 transition-all shadow-lg active:scale-95"
                      >
                        <Edit2 size={12} strokeWidth={3} /> Edit
                      </button>
                      <button 
                         onClick={() => handleDelete(prod.id)}
                         className="flex-1 h-9 bg-red-500 text-white rounded-lg text-[9px] font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-red-600 transition-all shadow-lg active:scale-95"
                      >
                        <Trash2 size={12} strokeWidth={3} /> Delete
                      </button>
                   </div>
                </div>
              </div>

              <div className="p-3 space-y-1 flex-1 flex flex-col">
                <h3 className="text-[11px] font-black text-[#0f172a] tracking-tight uppercase line-clamp-2 min-h-[2.5rem] leading-tight">
                  {prod.title}
                </h3>
                <div className="flex justify-between items-center pt-2 border-t border-gray-50 mt-auto">
                  <span className="text-sm font-black text-[#0f172a] tracking-tighter">
                    {formatPrice(prod.price)}
                  </span>
                  <span className="text-[7px] font-black text-gray-300 uppercase tracking-widest">{prod.category}</span>
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* PAGINATION INTERFACE */}
      {!loading && meta.totalPages > 1 && (
        <div className="flex items-center justify-center gap-4 py-8 border-t border-[#F2F2F2] mt-12 bg-white rounded-xl shadow-sm">
          <button
            disabled={currentPage === 1}
            onClick={() => fetchProducts(currentPage - 1)}
            className="h-10 px-6 rounded-lg border border-gray-200 text-[10px] font-black uppercase tracking-widest hover:bg-gray-50 disabled:opacity-30 transition-all flex items-center gap-2"
          >
            Previous Sector
          </button>
          <div className="flex items-center gap-3 px-6 px-10 border-x border-gray-100">
