                              ))}
                           </div>
                        </div>
                      )}

                      {formData.images.length > 0 ? (
                        <div className="space-y-4">
                           <p className="text-[10px] font-black text-gray-400 uppercase tracking-widest">Live Assets ({formData.images.length})</p>
