                              <img src={url} className="w-full aspect-square object-cover" alt="product" />
                              <button type="button" onClick={() => removeImage(idx)} className="absolute top-2 right-2 h-8 w-8 bg-white/95 backdrop-blur-sm rounded-lg flex items-center justify-center text-red-500 hover:bg-red-500 hover:text-white transition shadow-sm border border-gray-100">
                                 <X size={16} strokeWidth={2.5} />
                              </button>
                            </div>
                          ))}
                        </div>
                      ) : imagePreviews.length === 0 && (
                        <div className="aspect-square rounded-xl bg-gray-50 border border-gray-200 flex flex-col items-center justify-center text-gray-400">
                           <ImageIcon size={32} className="mb-2 text-gray-300" />
                           <span className="text-sm font-medium">No images uploaded</span>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  );
}

import { useState, useEffect } from "react";
import { api } from "../../api/client";
import { mapReview } from "../../api/dynamicMapper";
import { 
  Check, 
  Trash2, 
  MessageSquare, 
  Star, 
  Filter, 
  Sparkles, 
  User as UserIcon, 
  Zap, 
  Search,
  MoreVertical,
  ThumbsUp,
  Clock,
  ShieldCheck,
  AlertCircle,
  Activity
} from "lucide-react";
import toast from "react-hot-toast";
import { motion, AnimatePresence } from "framer-motion";
import Button from "../../components/ui/Button";

export default function Reviews() {
  const [reviews, setReviews] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState("");

  const fetchReviews = async () => {
    try {
      setLoading(true);
      const res = await api.get("/reviews/admin/list");
      const data = res.data || res.reviews || res || [];
      const mapped = Array.isArray(data) ? data.map(mapReview) : [];
      setReviews(mapped);
    } catch (err) {
      toast.error("Cloud synchronization failed");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchReviews();
  }, []);

  const handleApprove = async (id) => {
    try {
      await api.put(`/reviews/admin/${id}/approve`);
      toast.success("Sentiment Validated & Published");
      fetchReviews();
    } catch {
      toast.error("Activation Failure");
    }
  };

  const handleDelete = async (id) => {
    if (!window.confirm("Permanently archive this review signal?")) return;
    try {
      await api.delete(`/reviews/admin/${id}`);
      toast.success("Signal Purged Successfully");
      fetchReviews();
    } catch {
      toast.error("Purge Protocol Failure");
    }
  };

  const filtered = reviews.filter(r => 
    r.user?.toLowerCase().includes(search.toLowerCase()) || 
    r.product?.toLowerCase().includes(search.toLowerCase()) ||
    r.comment?.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="max-w-6xl mx-auto space-y-8 pb-12">
      {/* 🏙️ MODERN HEADER */}
      <div className="flex flex-col sm:flex-row sm:items-end justify-between gap-6 border-b border-slate-100 pb-8">
        <div className="space-y-1">
          <div className="flex items-center gap-2 mb-2">
