      className={`bg-white rounded-2xl shadow-sm overflow-hidden hover:shadow-2xl transition-all flex flex-col h-full relative group ${product.type === 'FULL_OUTFIT' ? 'ring-1 ring-indigo-50 border-indigo-100' : ''}`}
    >
      <Link to={(product._id || product.id) ? `/product/${product._id || product.id}` : "/collection"} className="flex flex-col h-full">
        {/* IMAGE */}
        <div
          className="relative h-48 overflow-hidden bg-gray-50 border-b border-gray-50"
          onMouseEnter={() => setIsHovered(true)}
          onMouseLeave={() => setIsHovered(false)}
        >
          <img
            src={getOptimizedImage(product.images?.[0] || product.image)}
            loading="lazy"
            className="w-full h-full object-cover transition-transform duration-500 group-hover:scale-110"
            alt={product.title}
          />

          {/* BADGES */}
          <div className="absolute top-2 left-2 z-20 flex flex-col gap-1.5">
             {product.type === 'FULL_OUTFIT' && (
               <motion.div 
                 animate={{ opacity: [0.8, 1, 0.8], scale: [0.98, 1, 0.98] }}
                 transition={{ duration: 2, repeat: Infinity, ease: "easeInOut" }}
                 className="bg-indigo-600 text-white px-2 py-1 rounded-md text-[8px] font-black uppercase tracking-widest flex items-center gap-1 shadow-lg"
               >
                 <Sparkles size={10} className="fill-white" /> Full Outfit
               </motion.div>
             )}
             {discount > 0 && (
               <motion.div 
                 animate={{ y: [0, -2, 0] }}
                 transition={{ duration: 3, repeat: Infinity, ease: "easeInOut" }}
                 className="bg-[#0f172a] text-white px-2 py-1 rounded-md text-[8px] font-black uppercase tracking-widest shadow-lg"
               >
                 {Math.round(discount)}% OFF
               </motion.div>
             )}
          </div>

          <button
            type="button"
            onClick={handleWishlist}
            className={`absolute top-2 right-2 z-20 p-1.5 backdrop-blur-md rounded-full transition-all shadow-sm border ${
              isWishlisted 
                ? "bg-red-500 text-white border-red-500" 
                : "bg-white/95 text-gray-400 border-gray-100 hover:text-red-500"
            }`}
            aria-label="Add to wishlist"
          >
            <Heart size={16} fill={isWishlisted ? "currentColor" : "none"} strokeWidth={isWishlisted ? 0 : 2} />
          </button>

          {/* ADD TO CART OVERLAY */}
          <div className="absolute bottom-2 left-2 right-2 z-20">
            <motion.button
              whileTap={{ scale: 0.92 }}
              transition={{ type: "spring", stiffness: 400, damping: 17 }}
              type="button"
              onClick={handleAddToCart}
              className="w-full py-2.5 bg-[#0f172a] text-white text-[10px] font-black uppercase tracking-widest rounded-xl shadow-xl flex items-center justify-center gap-2 hover:bg-black transition-colors"
            >
              <ShoppingBag size={14} /> Add to bag
            </motion.button>
          </div>

          {/* QUICK SIZE SELECTOR OVERLAY */}
          <AnimatePresence>
            {showSizeSelector && (
              <QuickSizeSelector 
                product={product} 
                onSelect={handleQuickSelect} 
                onClose={() => setShowSizeSelector(false)} 
              />
            )}
          </AnimatePresence>
        </div>

        {/* CONTENT */}
        <div className="p-3 space-y-1 flex-1 flex flex-col justify-end">
          <div className="space-y-1">
            <div className="flex justify-between items-start">
              <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest leading-none mb-1">
                {product.category || "General"}
              </span>
            </div>
            <h3 className="text-sm font-bold text-gray-900 line-clamp-2 leading-tight">
              {product.title}
            </h3>
          </div>

          <div className="flex items-center justify-between pt-2">
            <span className="text-base font-black text-gray-900 tracking-tighter">
              {formatPrice(product.price)}
            </span>
            {product.type === 'FULL_OUTFIT' && (
              <span className="text-[8px] font-black text-indigo-400 uppercase tracking-widest bg-indigo-50 px-1.5 py-0.5 rounded leading-none">
                Combo Set
              </span>
            )}
          </div>
        </div>
      </Link>
    </motion.div>
  );
}

export default memo(ProductCard);

import { useState } from "react";
import { X, ShoppingBag } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export default function QuickSizeSelector({ product, onSelect, onClose }) {
  const [topSize, setTopSize] = useState("");
  const [bottomSize, setBottomSize] = useState("");

  const topOptions = ["S", "M", "L", "XL", "XXL"];
  const bottomOptions = ["28", "30", "32", "34", "36", "38"];

  const handleAdd = () => {
    if (!topSize || !bottomSize) return;
    onSelect({ topSize, bottomSize });
  };

  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      exit={{ opacity: 0, scale: 0.95 }}
      className="absolute inset-0 z-50 bg-white/95 backdrop-blur-md p-4 flex flex-col justify-between"
    >
      <div className="flex justify-between items-center mb-2">
        <h4 className="text-[10px] font-black uppercase tracking-widest text-gray-400">Select Sizes</h4>
        <button onClick={onClose} className="p-1 hover:bg-gray-100 rounded-full transition-colors">
          <X size={14} className="text-gray-900" />
        </button>
      </div>

      <div className="space-y-4 flex-1 flex flex-col justify-center">
        <div>
          <p className="text-[8px] font-black text-gray-300 uppercase mb-2 tracking-widest">Topwear (T)</p>
          <div className="flex flex-wrap gap-1.5">
            {topOptions.map((s) => (
              <button
                key={s}
                onClick={() => setTopSize(s)}
                className={`h-7 px-2 min-w-[32px] rounded-md text-[9px] font-black transition-all border ${
                  topSize === s 
                    ? "bg-[#0f172a] text-white border-[#0f172a]" 
                    : "bg-white text-gray-400 border-gray-100 hover:border-gray-300"
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>

        <div>
          <p className="text-[8px] font-black text-gray-300 uppercase mb-2 tracking-widest">Bottomwear (B)</p>
          <div className="flex flex-wrap gap-1.5">
            {bottomOptions.map((s) => (
              <button
                key={s}
                onClick={() => setBottomSize(s)}
                className={`h-7 px-2 min-w-[32px] rounded-md text-[9px] font-black transition-all border ${
                  bottomSize === s 
                    ? "bg-[#0f172a] text-white border-[#0f172a]" 
                    : "bg-white text-gray-400 border-gray-100 hover:border-gray-300"
                }`}
              >
                {s}
              </button>
            ))}
          </div>
        </div>
      </div>

      <button
        onClick={handleAdd}
        disabled={!topSize || !bottomSize}
        className="w-full py-2.5 bg-[#0f172a] text-white text-[9px] font-black uppercase tracking-widest rounded-lg shadow-lg flex items-center justify-center gap-2 hover:bg-[#1e3a8a] transition-all disabled:opacity-30 active:scale-95 mt-4"
      >
        <ShoppingBag size={14} /> Confirm Selection
      </button>
    </motion.div>
  );
}

import { useState } from "react";
import { Plus, X, ChevronDown, ChevronUp, Sparkles } from "lucide-react";
import CouponCard from "../ui/CouponCard";

export default function CouponSection({ code, setCode, onApply, onRemove, isApplied, isLoading, subtotal, availableCoupons = [] }) {
  const [showOffers, setShowOffers] = useState(false);

  const activeCoupons = (availableCoupons || []).filter(c => c.status === "active");
  const upcomingCoupons = (availableCoupons || []).filter(c => c.status === "upcoming");

  return (
    <div className="bg-white border border-gray-100 rounded-2xl p-5 space-y-4 shadow-sm group hover:border-[#0f172a] transition-all">
      <div className="flex items-center justify-between pl-1">
        <div className="flex items-center gap-2">
          <div className="h-1 w-8 bg-[#0f172a] rounded-full group-hover:w-12 transition-all" />
          <span className="text-[10px] font-black text-gray-300 uppercase tracking-widest leading-none">Promotion Key</span>
        </div>

        {!isApplied && (activeCoupons.length > 0 || upcomingCoupons.length > 0) && (
          <button 
            onClick={() => setShowOffers(!showOffers)}
            className="flex items-center gap-1 text-[9px] font-black text-[#1e3a8a] bg-[#1e3a8a]/5 px-2 py-1 rounded-lg uppercase tracking-widest hover:bg-[#1e3a8a] hover:text-white transition-all shadow-sm"
          >
            {showOffers ? <ChevronUp size={10} /> : <ChevronDown size={10} />}
            {showOffers ? "Hide Logic" : "View Manifests"}
          </button>
        )}
      </div>

      {!isApplied && showOffers && (
        <div className="space-y-6 py-2 animate-in slide-in-from-top-4 duration-300">
          {/* ACTIVE SECTION */}
          {activeCoupons.length > 0 && (
            <div className="space-y-3">
              <div className="flex items-center gap-2 px-1">
                <div className="h-px flex-1 bg-green-100" />
                <span className="text-[8px] font-black text-green-600 uppercase tracking-widest">Live Manifests</span>
                <div className="h-px flex-1 bg-green-100" />
              </div>
              <div className="grid grid-cols-1 gap-3 max-h-[300px] overflow-y-auto pr-1">
                {activeCoupons.map((coupon) => (
                  <CouponCard 
                    key={coupon.id || coupon._id} 
                    coupon={coupon} 
                    onApply={(c) => {
                      setCode(c);
                      onApply(c);
                      setShowOffers(false);
                    }} 
                  />
                ))}
              </div>
            </div>
          )}

          {/* UPCOMING SECTION */}
          {upcomingCoupons.length > 0 && (
            <div className="space-y-3">
              <div className="flex items-center gap-2 px-1">
                <div className="h-px flex-1 bg-amber-100" />
                <span className="text-[8px] font-black text-amber-600 uppercase tracking-widest">Upcoming Sequences</span>
                <div className="h-px flex-1 bg-amber-100" />
              </div>
              <div className="grid grid-cols-1 gap-3 max-h-[300px] overflow-y-auto pr-1">
                {upcomingCoupons.map((coupon) => (
                  <CouponCard 
                    key={coupon.id || coupon._id} 
                    coupon={coupon} 
                  />
                ))}
              </div>
            </div>
          )}

          {activeCoupons.length === 0 && upcomingCoupons.length === 0 && (
            <div className="py-8 text-center bg-gray-50 rounded-xl border border-dashed border-gray-200">
               <p className="text-[10px] font-black uppercase tracking-widest text-gray-300">No offers available right now</p>
            </div>
          )}
        </div>
      )}

      <div className="relative">
        <input
          type="text"
          placeholder="ENTER DISCOUNT CODE"
          value={code}
          onChange={(e) => setCode(e.target.value.toUpperCase())}
          disabled={isApplied || isLoading}
          className="w-full h-12 pl-5 pr-28 bg-gray-50 border border-transparent rounded-xl text-xs font-black tracking-widest outline-none focus:bg-white focus:border-[#0f172a] transition-all uppercase placeholder:text-gray-200 disabled:opacity-50"
        />
        {!isApplied ? (
          <button
            onClick={() => onApply(code)}
            disabled={isLoading || !code.trim()}
            className="absolute right-1 top-1 bottom-1 px-5 bg-[#1e3a8a] text-white rounded-lg text-[9px] font-black uppercase tracking-[0.2em] hover:bg-black transition-all disabled:opacity-30 disabled:hover:scale-100 shadow-md flex items-center justify-center"
          >
            {isLoading ? "..." : <><Plus size={14} strokeWidth={4} className="mr-1" /> VALIDATE</>}
          </button>
        ) : (
          <button
            onClick={onRemove}
            className="absolute right-1 top-1 bottom-1 px-5 bg-red-50 text-red-500 rounded-lg text-[9px] font-black uppercase tracking-[0.2em] hover:bg-red-100 transition-all flex items-center justify-center border border-red-100"
          >
            <X size={14} strokeWidth={4} className="mr-1" /> EXTINGUISH
          </button>
        )}
      </div>

      {isApplied && (
        <div className="flex items-center gap-2 px-3 py-2 bg-green-50 rounded-lg border border-green-100">
           <div className="w-1.5 h-1.5 rounded-full bg-green-500 animate-pulse" />
           <p className="text-[9px] text-green-600 font-black uppercase tracking-widest">Access granted: Discount successfully injected.</p>
        </div>
      )}
    </div>
  );
}

import { Link, useLocation, useNavigate } from "react-router-dom";
import { Home, ShoppingCart, Heart, User, Search, X, Package } from "lucide-react";
import { useCartStore } from "../../store";
import clsx from "clsx";
import { motion } from "framer-motion";
import { useMemo, useState, createElement } from "react";
import { modalTransition, fadeIn, snappyTransition } from "../../utils/motion";
import { AnimatePresence } from "framer-motion";

export default function BottomNav() {
  void motion;
  const location = useLocation();
  const { items } = useCartStore();
  const navigate = useNavigate();

  const [searchOpen, setSearchOpen] = useState(false);
  const [query, setQuery] = useState("");

  const cartCount = useMemo(() => items?.length || 0, [items]);

  const links = [
    { to: "/", icon: Home },
    { to: "#search", icon: Search },
    { to: "/wishlist", icon: Heart },
    { to: "/cart", icon: ShoppingCart, badge: cartCount },
    { to: "/my-orders", icon: Package },
    { to: "/profile", icon: User },
  ];

  return (
    <>
      {/* Bottom Nav */}
      <motion.nav 
        initial={{ y: 100, opacity: 0 }}
        animate={{ y: 0, opacity: 1 }}
        transition={{ duration: 0.6, ease: [0.22, 1, 0.36, 1] }}
        className="md:hidden fixed bottom-6 left-0 right-0 z-50 px-6"
      >
        <div className="mx-auto max-w-sm relative">
          <div className="relative flex justify-between items-center h-16 px-4 rounded-3xl bg-white/90 backdrop-blur-xl border border-white/20 shadow-2xl">

            {links.map(({ to, icon: Icon, badge }) => {
              const isSearch = to === "#search";
              const isActive = !isSearch && location.pathname === to;

              const content = (
                <div className="relative flex items-center justify-center w-full">

                  <motion.div
                    whileTap={{ scale: 0.9 }}
                    whileHover={{ scale: 1.05 }}
                    className={clsx(
                      "relative p-2 rounded-xl transition-colors duration-300",
                      isActive
                        ? "text-white"
                        : "text-gray-400 hover:text-[#0f172a]"
                    )}
                  >
                    {isActive && (
                      <motion.div
                        layoutId="nav-pill"
                        className="absolute inset-0 bg-[#0f172a] rounded-xl -z-10 shadow-lg"
                        transition={{ type: "spring", bounce: 0.2, duration: 0.6 }}
                      />
                    )}

                    {createElement(Icon, {
                      size: 20,
                      className: clsx(
                        "transition-transform duration-300",
                        isActive && "scale-110"
                      ),
                    })}

                    {/* Badge */}
                    {badge > 0 && (
                      <span className="absolute -top-1 -right-1 h-4 w-4 flex items-center justify-center text-[8px] font-black text-[#0f172a] bg-white rounded-full shadow-sm border border-gray-100">
                        {badge}
                      </span>
                    )}
                  </motion.div>
                </div>
              );

              if (isSearch) {
                return (
                  <button
                    key={to}
                    onClick={() => setSearchOpen(true)}
                    className="w-full"
                  >
                    {content}
                  </button>
                );
              }

              return (
                <Link key={to} to={to} className="w-full">
                  {content}
                </Link>
              );
            })}
          </div>
        </div>
      </motion.nav>

      {/* Search Modal */}
      <AnimatePresence>
        {searchOpen && (
          <motion.div 
            variants={fadeIn}
            initial="hidden"
            animate="visible"
            exit="exit"
            className="fixed inset-0 z-[60] bg-[#0f172a]/40 backdrop-blur-md flex items-start justify-center pt-10 px-4"
          >
            <motion.div 
              variants={modalTransition}
              initial="hidden"
              animate="visible"
              exit="exit"
              className="w-full max-w-sm bg-white rounded-3xl p-10 border border-gray-100 shadow-[0_32px_64px_-12px_rgba(0,0,0,0.14)]"
            >
              <div className="flex justify-between items-center mb-8">
                <div className="space-y-1">
                  <span className="text-[10px] font-black text-[#0f172a] uppercase tracking-[0.3em] leading-none mb-4">Transmission Search</span>
                </div>
                <motion.button 
                  whileTap={{ scale: 0.9 }}
                  onClick={() => setSearchOpen(false)}
                >
                  <X size={20} className="text-gray-300 hover:text-black transition-colors" />
                </motion.button>
              </div>

              <div className="space-y-6">
                <div className="relative">
                  <input
                    autoFocus
                    value={query}
                    onChange={(e) => setQuery(e.target.value)}
                    placeholder="Search seasonal manifests..."
                    className="w-full px-6 py-4 text-sm font-bold rounded-2xl bg-gray-50 border-none focus:ring-2 focus:ring-[#0f172a] outline-none transition-all placeholder:text-gray-200"
                    onKeyDown={(e) => {
                      if (e.key === "Enter") {
                        setSearchOpen(false);
                        navigate(`/search?q=${query}`);
                      }
                    }}
                  />
                  <Search size={18} className="absolute right-6 top-1/2 -translate-y-1/2 text-gray-200" />
                </div>

                <motion.button
                  whileTap={{ scale: 0.96 }}
                  onClick={() => {
                    setSearchOpen(false);
                    navigate(`/search?q=${query}`);
                  }}
                  className="w-full py-4 rounded-2xl bg-[#0f172a] text-white text-[10px] font-black uppercase tracking-widest shadow-xl hover:bg-black transition-all"
                >
                  Explore Archive
                </motion.button>
              </div>
            </motion.div>
          </motion.div>
        )}
      </AnimatePresence>
    </>
  );
}

