import { useState } from "react";
import { Link, useNavigate } from "react-router-dom";
import toast from "react-hot-toast";
import { motion } from "framer-motion";
import { 
  ArrowRight, 
  Mail, 
  Lock, 
  ShieldCheck, 
  User as UserIcon, 
  Phone, 
  Eye, 
  EyeOff 
} from "lucide-react";
import { api } from "../api/client";
import { useForm } from "../hooks/useForm";
import { registerValidator } from "../utils/validation";

export default function Register() {
  const navigate = useNavigate();
  const [showPassword, setShowPassword] = useState(false);

  const { values, errors, isSubmitting, handleChange, handleSubmit } = useForm(
    { name: "", email: "", phone: "", password: "" },
    registerValidator
  );

  const getPasswordStrength = (pass) => {
    if (!pass) return { score: 0, label: "", color: "bg-gray-200" };
    if (pass.length < 6) return { score: 1, label: "Weak", color: "bg-red-500" };
    if (pass.length < 10) return { score: 2, label: "Medium", color: "bg-yellow-500" };
    return { score: 3, label: "Strong", color: "bg-green-500" };
  };

  const strength = getPasswordStrength(values.password);

  const handleEmailSignup = async (formValues) => {
    try {
      await api.post("/auth/register", formValues);
      toast.success("Check your email for the 6-digit code.");
      navigate(`/verify?email=${encodeURIComponent(formValues.email)}&purpose=signup`);
    } catch (err) {
      toast.error(err?.response?.data?.message || "Registration failed.");
    }
  };

  return (
    <motion.div
      initial={{ opacity: 0 }}
      animate={{ opacity: 1 }}
      className="min-h-[calc(100vh-5rem)] flex items-center justify-center px-4 py-12 bg-slate-50"
    >
      <div className="w-full max-w-[500px] flex flex-col items-center">
        <div className="flex items-center gap-3 mb-10">
          <div className="h-10 w-10 bg-[#1e3a8a] text-[#0f172a] rounded-lg flex items-center justify-center shadow-sm">
            <ShieldCheck size={20} strokeWidth={3} />
          </div>
          <div className="flex flex-col">
            <h1 className="text-xl font-black text-[#1e3a8a] tracking-tight uppercase leading-none">
              DOLLER <span className="text-[#0f172a]">Coach</span>
            </h1>
            <p className="text-[9px] font-black uppercase tracking-[0.2em] text-gray-400 mt-1 uppercase">
              (By Gangwani and Company)
            </p>
          </div>
        </div>

        <div className="w-full bg-white border border-[#F2F2F2] rounded-[2rem] p-10 shadow-sm">
          <div className="mb-10 space-y-2">
            <h2 className="text-3xl font-black text-[#0f172a] tracking-tighter uppercase leading-none">Membership</h2>
            <p className="text-[10px] text-gray-400 font-bold uppercase tracking-widest leading-relaxed">
              Create your profile to access exclusive seasonal manifests
            </p>
          </div>

          <form onSubmit={(e) => handleSubmit(e, handleEmailSignup)} className="space-y-6">
            <div className="space-y-2">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Full name</label>
              <div className="relative">
                <UserIcon className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type="text"
                  name="name"
                  value={values.name}
                  onChange={handleChange}
                  className={`w-full pl-12 pr-4 py-3 rounded-lg bg-white border ${errors.name ? 'border-red-500' : 'border-transparent'} text-[#0f172a] font-bold text-sm focus:border-[#1e3a8a] outline-none shadow-sm`}
                />
              </div>
              {errors.name && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.name}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Email</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type="email"
                  name="email"
                  value={values.email}
                  onChange={handleChange}
                  className={`w-full pl-12 pr-4 py-3 rounded-lg bg-white border ${errors.email ? 'border-red-500' : 'border-transparent'} text-[#0f172a] font-bold text-sm focus:border-[#1e3a8a] outline-none shadow-sm`}
                />
              </div>
              {errors.email && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.email}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Phone Number</label>
              <div className="relative">
                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type="tel"
                  name="phone"
                  value={values.phone}
                  onChange={handleChange}
                  placeholder="10-digit mobile number"
                  className={`w-full pl-12 pr-4 py-3 rounded-lg bg-white border ${errors.phone ? 'border-red-500' : 'border-transparent'} text-[#0f172a] font-bold text-sm focus:border-[#1e3a8a] outline-none shadow-sm`}
                />
              </div>
              {errors.phone && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.phone}</p>}
            </div>

            <div className="space-y-2">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Password</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type={showPassword ? "text" : "password"}
                  name="password"
                  value={values.password}
                  onChange={handleChange}
                  className={`w-full pl-12 pr-12 py-3 rounded-lg bg-white border ${errors.password ? 'border-red-500' : 'border-transparent'} text-[#0f172a] font-bold text-sm focus:border-[#1e3a8a] outline-none shadow-sm`}
                />
                <button
                  type="button"
                  onClick={() => setShowPassword(!showPassword)}
                  className="absolute right-4 top-1/2 -translate-y-1/2 text-gray-300 hover:text-gray-600 transition-colors"
                >
                  {showPassword ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
              {errors.password && <p className="text-[10px] text-red-500 font-bold ml-1">{errors.password}</p>}

              {values.password && (
                <div className="mt-2 space-y-1.5">
                  <div className="flex gap-1 h-1">
                    {[1, 2, 3].map((s) => (
                      <div key={s} className={`flex-1 rounded-full transition-all duration-300 ${strength.score >= s ? strength.color : "bg-gray-200"}`} />
                    ))}
                  </div>
                  <p className={`text-[8px] font-black uppercase tracking-widest text-right`} style={{ color: strength.color.replace('bg-', 'var(--tw-') }}>
                    {strength.label}
                  </p>
                </div>
              )}
            </div>

            <button
              type="submit"
              disabled={isSubmitting}
              className="w-full h-14 bg-[#0f172a] text-white rounded-2xl font-black uppercase tracking-widest text-xs shadow-md hover:bg-black transition-all flex items-center justify-center gap-2 disabled:opacity-50"
            >
              {isSubmitting ? "Registering..." : "Join Inner Circle"} <ArrowRight size={16} />
            </button>
          </form>

          <div className="mt-8 pt-6 border-t border-[#F2F2F2] text-center">
            <Link to="/login" className="text-sm font-semibold text-indigo-600 hover:underline">
              Already have an account?
            </Link>
          </div>
        </div>
      </div>
    </motion.div>
  );
}

import { useState } from "react";
import { Link, useNavigate, useSearchParams } from "react-router-dom";
import { api } from "../api/client";
import toast from "react-hot-toast";
import { Sparkles, ArrowRight, Lock, Key, Mail } from "lucide-react";

export default function ResetPassword() {
  const navigate = useNavigate();
  const [params] = useSearchParams();
  const [email, setEmail] = useState(params.get("email") || "");
  const [token, setToken] = useState(params.get("token") || "");
  const [newPassword, setNewPassword] = useState("");
  const [loading, setLoading] = useState(false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!email || !token || !newPassword) return toast.error("Complete the security logic");
    if (newPassword.length < 6) return toast.error("New password must be at least 6 characters");
    setLoading(true);
    try {
      await api.post("/auth/reset-password", {
        email,
        resetToken: token,
        newPassword,
      });
      toast.success("Security System Updated");
      navigate("/login");
    } catch (err) {
      toast.error(err?.response?.data?.message || "Reset sequence failed");
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen grid place-items-center py-8 bg-white px-4">
      <div className="w-full max-w-sm">
        <div className="bg-[#f1f5f9] border border-gray-100 rounded-xl p-8 shadow-sm">
          <div className="text-center mb-8">
            <div className="px-4 py-2 text-sm rounded-lg bg-[#0f172a] text-white hover:scale-[1.02] shadow-sm transition-all">
              <Sparkles size={12} className="text-[#1e3a8a]" strokeWidth={3} /> Doller Coach
            </div>
            <h2 className="text-lg font-black text-[#0f172a] tracking-tighter uppercase leading-none">Save logic</h2>
            <p className="text-[9px] text-gray-400 font-black mt-2 uppercase tracking-widest">Define new security entry</p>
          </div>

          <form onSubmit={handleSubmit} className="space-y-6">
            <div className="space-y-1.5">
              <label className="text-[10px] font-black text-gray-400 uppercase tracking-[0.2em] ml-2">Iduser Account</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={18} />
                <input
                  type="email"
                  placeholder="name@example.com"
                  value={email}
                  disabled
                  className="w-full pl-12 pr-4 py-4 rounded-xl bg-[#f1f5f9] border border-gray-200 text-gray-400 text-sm font-medium focus:outline-none transition-all shadow-inner cursor-not-allowed"
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">Token</label>
              <div className="relative">
                <Key className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type="text"
                  placeholder="SECURITY_TOKEN"
                  value={token}
                  onChange={(e) => setToken(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 rounded-lg bg-white border border-transparent text-[#0f172a] font-black uppercase tracking-widest text-xs focus:border-[#1e3a8a] outline-none transition-all shadow-sm"
                />
              </div>
            </div>

            <div className="space-y-1">
              <label className="text-[9px] font-black text-gray-400 uppercase tracking-widest ml-1">New Key</label>
              <div className="relative">
                <Lock className="absolute left-4 top-1/2 -translate-y-1/2 text-gray-300" size={16} />
                <input
                  type="password"
                  placeholder="••••••••"
                  value={newPassword}
                  onChange={(e) => setNewPassword(e.target.value)}
                  className="w-full pl-12 pr-4 py-3 rounded-lg bg-white border border-transparent text-[#0f172a] font-black uppercase tracking-widest text-xs focus:border-[#1e3a8a] outline-none transition-all shadow-sm"
                />
              </div>
            </div>

            <button
              type="submit"
              disabled={loading}
              className="w-full py-5 bg-[#1e3a8a] text-[#0f172a] rounded-full text-[13px] font-black uppercase tracking-widest shadow-sm hover:shadow-sm hover:-translate-y-1 active:scale-95 disabled:opacity-50 transition-all flex items-center justify-center gap-3"
            >
              {loading ? "Saveing..." : "Update System"} <ArrowRight size={18} strokeWidth={3} />
            </button>
          </form>

          <div className="mt-8 text-center border-t border-gray-100 pt-6">
            <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest leading-relaxed mb-4">
               Iduser will be updated across all endpoints.
            </p>
            <p className="text-[9px] font-bold text-gray-400 uppercase tracking-widest">
              Abort recovery? <Link to="/login" className="text-[#0f172a] font-black hover:text-[#1e3a8a] transition-colors underline underline-offset-4">Login</Link>
            </p>
          </div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useState } from "react";
import { useSearchParams, useNavigate } from "react-router-dom";
import { api } from "../api/client";
import { mapProduct } from "../api/dynamicMapper";
import ProductCard from "../components/ProductCard";
import toast from "react-hot-toast";
import { Sparkles, Search as SearchIcon, ArrowRight, ShoppingBag, Zap, ShieldCheck } from "lucide-react";
import { motion, AnimatePresence } from "framer-motion";

export default function Search() {
  const [params] = useSearchParams();
  const navigate = useNavigate();
  const q = params.get("q") || "";
  const [products, setProducts] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let cancelled = false;
    const run = async () => {
      setLoading(true);
      try {
        if (!q.trim()) {
          setProducts([]);
          return;
        }
        const res = await api.get(`/products?q=${encodeURIComponent(q)}`);
        const data = Array.isArray(res) ? res : Array.isArray(res?.data) ? res.data : Array.isArray(res?.items) ? res.items : [];
        if (!cancelled) {
          setProducts(Array.isArray(data) ? data.map(mapProduct) : []);
        }
      } catch {
        toast.error("Error loading: Search Database");
      } finally {
        if (!cancelled) setLoading(false);
      }
    };
    run();
    return () => { cancelled = true; };
  }, [q]);

  return (
    <motion.div 
      initial={{ opacity: 0 }} 
      animate={{ opacity: 1 }}
      className="min-h-screen bg-white pt-4 pb-32"
    >
      <div className="max-w-[1400px] mx-auto px-6 md:px-10 space-y-10">

        {/* INQUIRY HEADER */}
        <div className="flex justify-between items-end border-b border-[#F2F2F2] pb-6">
          <div className="space-y-2">
            <div className="flex items-center gap-2">
               <SearchIcon size={14} className="text-[#1e3a8a]" strokeWidth={3} />
               <p className="text-[9px] font-black text-gray-300 uppercase tracking-widest italic">
                 Search Index
               </p>
            </div>
            <h1 className="text-3xl md:text-4xl font-black tracking-tighter text-[#0f172a] uppercase leading-none flex items-center gap-3">
              Results <span className="text-base md:text-lg font-black text-[#1e3a8a]">[{products.length}]</span>
